import{n as e,t}from"./en-BeAvWqrp.js";import{t as n}from"./merge-9Qs9NaoX.js";var r=n(t,{auth:{nav:{signIn:`Войти`,createAccount:`Создать аккаунт`,mobileTagline:`Единый копировщик для каждого сигнала Telegram`,backHome:`На главную`},oauth:{continueWithGoogle:`Продолжить с Google`,orDivider:`или`},login:{heading:`Вход в TScopier`,noAccount:`Нет аккаунта?`,signUpLink:`Зарегистрироваться`,footerPrompt:`Впервые в TScopier?`,footerLink:`Создать бесплатный аккаунт`,email:`Эл. почта`,emailPlaceholder:`you@example.com`,password:`Пароль`,passwordPlaceholder:`Введите пароль`,forgotPassword:`Забыли пароль?`,passwordResetSuccess:`Пароль обновлён. Теперь вы можете войти.`,submit:`Войти`},forgotPassword:{heading:`Сброс пароля`,subtitle:`Введите e-mail вашего аккаунта. Если он существует, мы отправим ссылку для сброса пароля.`,email:`Эл. почта`,emailPlaceholder:`you@example.com`,submit:`Отправить ссылку`,sentHeading:`Проверьте почту`,sentSubtitle:`Если аккаунт для {email} существует, вы скоро получите ссылку для сброса пароля.`,sentHint:`Проверьте папку «Спам», если письмо не пришло в течение нескольких минут.`,backToLogin:`Вернуться ко входу`},resetPassword:{heading:`Новый пароль`,subtitle:`Введите и подтвердите новый пароль ниже.`,password:`Новый пароль`,passwordPlaceholder:`Введите новый пароль`,confirmPassword:`Подтвердите пароль`,confirmPasswordPlaceholder:`Повторите новый пароль`,passwordHint:`Не менее 6 символов`,passwordTooShort:`Пароль должен содержать не менее 6 символов`,passwordMismatch:`Пароли не совпадают`,submit:`Обновить пароль`,invalidHeading:`Ссылка недействительна или устарела`,invalidSubtitle:`Эта ссылка больше не действительна. Запросите новую, чтобы продолжить.`,requestNewLink:`Запросить новую ссылку`,backToLogin:`Вернуться ко входу`},signup:{heading:`Создайте аккаунт`,hasAccount:`Уже есть аккаунт?`,signInLink:`Войти`,footerPrompt:`Уже есть аккаунт?`,footerLink:`Войти`,firstName:`Имя`,firstNamePlaceholder:`Имя`,lastName:`Фамилия`,lastNamePlaceholder:`Фамилия`,email:`Эл. почта`,emailPlaceholder:`you@example.com`,password:`Пароль`,passwordPlaceholder:`Выберите пароль`,confirmPassword:`Подтвердите пароль`,confirmPasswordPlaceholder:`Повторите пароль`,passwordHint:`Не менее 6 символов`,passwordTooShort:`Пароль должен содержать не менее 6 символов`,passwordMismatch:`Пароли не совпадают`,submit:`Создать аккаунт`,terms:{prefix:`Регистрируясь, вы соглашаетесь с нашими`,termsOfService:`Условиями использования`,conjunction:` и `,privacyPolicy:`Политикой конфиденциальности`}},verify:{heading:`Проверьте почту`,subtitle:`Мы только что отправили ссылку для подтверждения на {email}.`,resend:`Отправить снова`,resent:`Письмо отправлено!`,backToLogin:`Вернуться ко входу`},marketing:{headline:`Единый копировщик для каждого сигнала Telegram`,trustpilotLabel:`Trustpilot`,reviews:e,copyright:`© {year} Tartarix Inc.`},language:{label:`Язык`,choose:`Выберите язык`,searchPlaceholder:`Поиск языков…`,noResults:`Языки не найдены`},theme:{light:`Светлая тема`,dark:`Тёмная тема`,switchToLight:`Переключить на светлую тему`,switchToDark:`Переключить на тёмную тему`}},contactSupportPage:{channelsTitle:`Чем мы можем помочь?`,channelsSubtitle:`Свяжитесь с командой TSCopier по электронной почте, откройте документацию или начните чат в реальном времени.`,email:{title:`Поддержка по e-mail`,description:`Отправьте вопросы по аккаунту, биллингу или копированию сделок - обычно мы отвечаем в течение одного рабочего дня.`,cta:`Написать в поддержку`},docs:{title:`Документация`,description:`Пошаговые инструкции по подключению брокеров, каналов Telegram, торговых стилей и устранению неполадок.`,cta:`Открыть документацию`},liveChat:{title:`Онлайн-чат`,description:`Общайтесь с нами в реальном времени и получите быструю помощь по настройке прямо в панели управления.`,cta:`Начать чат`},faq:{title:`Часто задаваемые вопросы`,subtitle:`Краткие ответы перед обращением в поддержку.`,items:[{question:`Как подключить мой аккаунт MetaTrader?`,answer:`Откройте раздел конфигурации, добавьте брокерский аккаунт, введите данные входа MetaTrader и дождитесь статуса подключения. Для каждого подключенного аккаунта нужно сохранить торговый стиль, размер лота и выбор канала до начала копирования.`},{question:`Почему сигналы из Telegram не копируются?`,answer:`Проверьте, что брокер подключен, канал Telegram привязан и активен, этот канал выбран у брокера в конфигурации, подписка активна, а e-mail подтвержден. Просмотрите Copier Logs: там могут быть причины пропуска, например фильтры канала, новостной blackout или отсутствие SL/TP в сигнале.`},{question:`Как добавить канал сигналов Telegram?`,answer:`Перейдите в раздел каналов, при необходимости подключите Telegram, затем добавьте имя пользователя канала или ссылку-приглашение. Включите канал и назначьте его тем брокерским аккаунтам в конфигурации, которые должны копировать сигналы.`},{question:`Что делает blackout новостей / экономического календаря?`,answer:`Когда торговля на новостях отключена для аккаунта, TSCopier может приостанавливать новые входы и при необходимости закрывать открытые сделки вокруг событий с высоким влиянием. Используйте страницу экономического календаря для просмотра предстоящих публикаций и настройки правил в конфигурации аккаунта.`},{question:`Нужна ли платная подписка для копирования сделок?`,answer:`Для исполнения Telegram-копирования в реальном времени требуется активный платный план. При наличии пробного периода вы все равно можете изучать панель и настройки; актуальный план и статус продления смотрите в биллинге.`},{question:`Почему нужно подтвердить e-mail перед использованием платформы?`,answer:`Подтверждение e-mail защищает вход и позволяет отправлять вам квитанции об оплате и важные уведомления по аккаунту. Если вы застряли на экране подтверждения, воспользуйтесь повторной отправкой письма или обратитесь в поддержку с адресом, который использовали при регистрации.`},{question:`Брокер отображается как отключенный - что делать?`,answer:`Убедитесь, что MetaTrader работает на стороне брокера, учетные данные остаются действительными, а аккаунт не заблокирован. Обновите подключение в конфигурации и проверьте Copier Logs на ошибки сессии. Если проблема сохраняется, напишите в поддержку и укажите имя брокера и логин аккаунта (никогда не отправляйте пароль).`},{question:`Можно ли копировать один и тот же канал на нескольких брокеров?`,answer:`Да. Подключите каждый аккаунт MetaTrader отдельно в конфигурации и выберите один и тот же канал Telegram для каждого брокера. Размер лота, торговый стиль и параметры риска настраиваются отдельно для каждого аккаунта.`}]}},riskDisclaimerPage:{title:`Предупреждение о рисках`,intro:`Торговля на рынке Forex, CFD и другими инструментами с кредитным плечом связана со значительным риском убытков. TSCopier — это инструмент копирования сделок, а не брокер, инвестиционный советник или финансовый планировщик. Ничто на этой странице не является финансовой рекомендацией. Вы несете полную ответственность за свои торговые решения и любые убытки.`,sections:[{title:`Общие торговые риски`,paragraphs:[`Вы можете потерять часть или весь внесенный капитал. Кредитное плечо усиливает как прибыль, так и убытки. Прошлые результаты поставщика сигналов, бэктеста или вашей собственной истории не гарантируют будущие результаты.`,`Рынки могут открываться гэпами, приостанавливаться или двигаться крайне резко во время новостей. TSCopier не гарантирует, что сигналы будут получены, корректно распознаны или исполнены по определенной цене и в определенное время.`]},{title:`Риски поставщика сигналов`,paragraphs:[`Копируйте только тех поставщиков сигналов, которым вы доверяете и которых понимаете. У поставщиков могут быть стимулы, противоречащие вашим интересам. Маркетинговые скриншоты, заявления о высокой доле прибыльных сделок и выборочные результаты могут не отражать ваш реальный опыт с учетом счета, лота, брокера и задержки.`,`По возможности проверяйте результаты независимо. Поставщик, который подходит другим, может не подходить вам по уровню риска, размеру счета или торговому времени.`]},{title:`Репейнтинг и манипуляции в каналах`,paragraphs:[`Некоторые Telegram-каналы с сигналами редактируют или удаляют сообщения после неудачной сделки, чтобы публичная лента выглядела безупречно. «Успешный» сигнал мог быть переписан, а убыточный — полностью исчезнуть.`,`Не полагайтесь только на видимую историю канала или сторонние скриншоты. Сверяйте данные с вашими Copier Logs, брокерскими выписками и записями с отметками времени. Репейнтинг позволяет поставщикам выглядеть более точными, чем они есть на самом деле.`]},{title:`Ограничения парсинга и исполнения`,paragraphs:[`Сигналы автоматически интерпретируются из текста. Опечатки в stop loss (SL) или take profit (TP) — неверные цифры, пропущенные десятичные знаки, неоднозначные символы или смешанные единицы — могут приводить к некорректным ценам. TSCopier может пропустить сигнал, игнорировать неверные уровни или применить значения по умолчанию из вашей конфигурации вместо замысла поставщика.`,`Фактическое исполнение может отличаться от входа поставщика: проскальзывание, реквоты, частичное исполнение, правила минимальной дистанции и разрывы сессии у брокера влияют на результат. Режимы strict entry, range pending и multi-leg добавляют дополнительную сложность. Всегда проверяйте открытые позиции у вашего брокера.`]},{title:`Операционные и конфигурационные риски`,paragraphs:[`Блокировки на новостях, фильтры каналов, цели по прибыли, лимиты максимального убытка, статус подписки и настройки по каждому каналу могут блокировать или изменять копирование. Неверно настроенный размер лота, сопоставление символов или неподключенные каналы часто приводят к тому, что сделки не копируются как ожидается.`,`Автоматическое закрытие при достижении лимитов закрывает сделки, привязанные к каналу, на стороне TSCopier, но не может отменить уже понесенный рыночный убыток. Изменения конфигурации вступают в силу после сохранения — несохраненные черновики не защищают ваш счет.`]},{title:`Оставайтесь вовлечены при копировании`,paragraphs:[`Автоматическое копирование — не формат «настроил и забыл». Регулярно контролируйте открытые сделки, equity, margin и Copier Logs. Вмешивайтесь через брокера, когда условия меняются или когда вы больше не согласны с уровнем риска поставщика.`,`Если вы не можете активно контролировать свой счет, копирование сигналов в реальном времени может вам не подходить.`]},{title:`Как повысить свои шансы (не рекомендация)`,paragraphs:[`Начинайте с демо-счета или с минимального реального объема, потерю которого вы можете себе позволить. Оценивайте каналы на дистанции; используйте бэктесты, где это возможно; включайте лимиты максимального убытка и цели по прибыли; настраивайте фильтры каналов; диверсифицируйте поставщиков, а не концентрируйте риск.`,`Читайте причины пропуска в Copier Logs, когда сигналы не открываются в сделки. Сохраняйте реалистичные ожидания — стабильное небольшое преимущество при строгом контроле риска существенно отличается от маркетинга в стиле «быстро разбогатеть».`]}],closing:`Используя TSCopier, вы подтверждаете, что торговля связана с риском, поставщики сигналов могут быть ненадежными или вводить в заблуждение, и вы принимаете полную ответственность за все сделки на ваших подключенных счетах.`}});export{r as ru};